<?php require_once 'db.php'; $messages=[]; try{ if(file_exists(APP_INSTALLED_FLAG)) throw new Exception('Application is already installed. Delete .installed to reinstall intentionally.'); $server=pdo(false); $server->exec('CREATE DATABASE IF NOT EXISTS `'.str_replace('`','',DB_NAME).'` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci'); $pdo=pdo(); $sql=file_get_contents(__DIR__.'/schema.sql'); foreach(array_filter(array_map('trim',explode(';',$sql))) as $stmt){ $pdo->exec($stmt); } foreach(['admin','student','librarian'] as $r){ $pdo->prepare('INSERT IGNORE INTO roles(name) VALUES(?)')->execute([$r]); } $themes=[['Aurora','aurora','#7c3aed','#22d3ee'],['Midnight','midnight','#0f172a','#38bdf8'],['Emerald','emerald','#047857','#a7f3d0'],['Ruby','ruby','#be123c','#fb7185'],['Solar','solar','#f59e0b','#fde68a'],['Ocean','ocean','#0369a1','#67e8f9'],['Royal','royal','#4338ca','#c4b5fd'],['Cyber','cyber','#16a34a','#86efac'],['Rose Gold','rose-gold','#e11d48','#f9a8d4'],['Graphite','graphite','#374151','#d1d5db']]; foreach($themes as $t){$pdo->prepare('INSERT IGNORE INTO themes(name,slug,primary_color,accent_color) VALUES(?,?,?,?)')->execute($t);} $roles=$pdo->query('SELECT name,id FROM roles')->fetchAll(PDO::FETCH_KEY_PAIR); $adminPass=password_hash('Admin@123',PASSWORD_DEFAULT); $libPass=password_hash('Librarian@123',PASSWORD_DEFAULT); $pdo->prepare('INSERT IGNORE INTO users(role_id,name,email,password,status) VALUES(?,?,?,?,"active")')->execute([$roles['admin'],'System Admin','admin@library.test',$adminPass]); $pdo->prepare('INSERT IGNORE INTO users(role_id,name,email,password,status) VALUES(?,?,?,?,"active")')->execute([$roles['librarian'],'Default Librarian','librarian@library.test',$libPass]); $libId=$pdo->lastInsertId() ?: $pdo->query("SELECT id FROM users WHERE email='librarian@library.test'")->fetchColumn(); $pdo->prepare('INSERT IGNORE INTO librarians(user_id,employee_code) VALUES(?,?)')->execute([$libId,'LIB-001']); for($i=1;$i<=48;$i++){ $pdo->prepare('INSERT IGNORE INTO library_tables(table_code,floor_no,zone,capacity,status) VALUES(?,?,?,?,"available")')->execute(['T'.str_pad($i,2,'0',STR_PAD_LEFT),ceil($i/16),chr(64+ceil($i/16)),1]); } file_put_contents(APP_INSTALLED_FLAG,date('c')); $messages[]='Installation complete. Admin: admin@library.test / Admin@123; Librarian: librarian@library.test / Librarian@123'; }catch(Throwable $e){ $messages[]=$e->getMessage(); } app_header('Install'); ?><section class="card wide"><h1>Installer</h1><?php foreach($messages as $m): ?><p><?=e($m)?></p><?php endforeach; ?><a class="btn" href="login.php">Go to login</a></section><?php app_footer(); ?>
